`COL1` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci
) ENGINE = InnoDB CHARACTER SET = utf8mb4 COLLATE = utf8mb4_bin ROW_FORMAT = Compact;
